   173	  bool success = ioctl(sock_fd, SIOCGIFFLAGS, (caddr_t)&ifr) == 0;
   174	  if (!success && if_action == INTERFACE_DOWN && errno == ENODEV) {
   175	    LOG_W(OIP, "trying to remove non-existant device %s\n", ifn);
   176	    return true;
   177	  }
   178	  LOG_D(OIP, "Got flags for %s: 0x%x (action: %s)\n", ifn, ifr.ifr_flags, action);
